package config

import (
	"crypto/x509"
	"crypto/x509/pkix"
	"time"

	couchbasev2 "github.com/couchbase/couchbase-operator/pkg/apis/couchbase/v2"
	util_x509 "github.com/couchbase/couchbase-operator/pkg/util/x509"

	admissionregistrationv1beta1 "k8s.io/api/admissionregistration/v1beta1"
	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	rbacv1 "k8s.io/api/rbac/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/util/intstr"
)

const (
	// AdmissionResourceName is the name used for all resources generated by the individual functions.
	AdmissionResourceName = "couchbase-operator-admission"
)

// DumpAdmissionYAML dumps all admission controller resources to standard out.
func DumpAdmissionYAML(conf *Config) error {
	if conf.NoAdmission {
		return nil
	}

	// Generate TLS configuration for the dynamic admission controller.
	validFrom := time.Now()
	validTo := time.Now().Add(24 * 365 * 10 * time.Hour)
	ca, _ := util_x509.NewCertificateAuthority(util_x509.KeyTypeRSA, AdmissionResourceName+" CA", validFrom, validTo, util_x509.CertTypeCA)
	req := util_x509.KeyPairRequest{
		KeyType:   util_x509.KeyTypeRSA,
		CertType:  util_x509.CertTypeServer,
		ValidFrom: validFrom,
		ValidTo:   validTo,
		Req: &x509.CertificateRequest{
			Subject: pkix.Name{
				CommonName: AdmissionResourceName,
			},
			DNSNames: []string{
				AdmissionResourceName + "." + conf.Namespace + ".svc",
			},
		},
	}
	key, cert, _ := req.Generate(ca)

	// Create resources.
	if err := DumpYAML(conf, "admission-service-account", GetAdmissionServiceAccount()); err != nil {
		return err
	}
	if err := DumpYAML(conf, "admission-cluster-role", GetAdmissionClusterRole()); err != nil {
		return err
	}
	if err := DumpYAML(conf, "admission-cluster-role-binding", GetAdmissionClusterRoleBinding(conf.Namespace)); err != nil {
		return err
	}
	if err := DumpYAML(conf, "admission-secret", GetAdmissionSecret(key, cert)); err != nil {
		return err
	}
	if err := DumpYAML(conf, "admission-deployment", GetAdmissionDeployment(conf.AdmissionImage, conf.ImagePullSecret)); err != nil {
		return err
	}
	if err := DumpYAML(conf, "admission-service", GetAdmissionService()); err != nil {
		return err
	}
	if err := DumpYAML(conf, "admission-mutating-webhook", GetAdmissionMutatingWebhook(conf.Namespace, ca.Certificate)); err != nil {
		return err
	}
	if err := DumpYAML(conf, "admission-validating-webhook", GetAdmissionValidatingWebhook(conf.Namespace, ca.Certificate)); err != nil {
		return err
	}
	return nil
}

// GetAdmissionClusterRole return the cluster role to run with.
func GetAdmissionClusterRole() *rbacv1.ClusterRole {
	return &rbacv1.ClusterRole{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "rbac.authorization.k8s.io/v1",
			Kind:       "ClusterRole",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: AdmissionResourceName,
		},
		Rules: []rbacv1.PolicyRule{
			{
				APIGroups: []string{
					couchbasev2.GroupName,
				},
				Resources: []string{
					couchbasev2.ClusterCRDResourcePlural,
					couchbasev2.BucketCRDResourcePlural,
					couchbasev2.EphemeralBucketCRDResourcePlural,
					couchbasev2.MemcachedBucketCRDResourcePlural,
					couchbasev2.ReplicationCRDResourcePlural,
					couchbasev2.UserCRDResourcePlural,
					couchbasev2.GroupCRDResourcePlural,
					couchbasev2.RoleCRDResourcePlural,
					couchbasev2.RoleBindingCRDResourcePlural,
				},
				Verbs: []string{
					"list",
				},
			},
			{
				APIGroups: []string{
					"",
				},
				Resources: []string{
					"namespaces",
					"secrets",
				},
				Verbs: []string{
					"get",
				},
			},
			{
				APIGroups: []string{
					"storage.k8s.io",
				},
				Resources: []string{
					"storageclasses",
				},
				Verbs: []string{
					"get",
				},
			},
		},
	}
}

// GetAdmissionServiceAccount get the service account to run as.
func GetAdmissionServiceAccount() *corev1.ServiceAccount {
	return &corev1.ServiceAccount{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "v1",
			Kind:       "ServiceAccount",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: AdmissionResourceName,
		},
	}
}

// GetAdmissionClusterRoleBinding generates the cluster role binding linking the role to the service account.
func GetAdmissionClusterRoleBinding(namespace string) *rbacv1.ClusterRoleBinding {
	return &rbacv1.ClusterRoleBinding{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "rbac.authorization.k8s.io/v1",
			Kind:       "ClusterRoleBinding",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: AdmissionResourceName,
		},
		Subjects: []rbacv1.Subject{
			{
				Kind:      "ServiceAccount",
				Name:      AdmissionResourceName,
				Namespace: namespace,
			},
		},
		RoleRef: rbacv1.RoleRef{
			APIGroup: "rbac.authorization.k8s.io",
			Kind:     "ClusterRole",
			Name:     AdmissionResourceName,
		},
	}
}

// GetAdmissionSecret generates the TLS secret providing server certificates.
func GetAdmissionSecret(key, cert []byte) *corev1.Secret {
	return &corev1.Secret{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "v1",
			Kind:       "Secret",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: AdmissionResourceName,
		},
		Data: map[string][]byte{
			"tls-cert-file":        cert,
			"tls-private-key-file": key,
		},
	}
}

// GetAdmissionDeployment returns the canonical deployment for the admission controller.
func GetAdmissionDeployment(image, imagePullSecret string, extraArgs ...string) *appsv1.Deployment {
	replicas := int32(1)
	deployment := &appsv1.Deployment{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "apps/v1",
			Kind:       "Deployment",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: AdmissionResourceName,
		},
		Spec: appsv1.DeploymentSpec{
			Replicas: &replicas,
			Selector: &metav1.LabelSelector{
				MatchLabels: map[string]string{
					"app": AdmissionResourceName,
				},
			},
			Template: corev1.PodTemplateSpec{
				ObjectMeta: metav1.ObjectMeta{
					Labels: map[string]string{
						"app": AdmissionResourceName,
					},
				},
				Spec: corev1.PodSpec{
					ServiceAccountName: AdmissionResourceName,
					Containers: []corev1.Container{
						{
							Name:  AdmissionResourceName,
							Image: image,
							Command: []string{
								"couchbase-operator-admission",
							},
							Args: append([]string{
								"--logtostderr",
								"--stderrthreshold", "0",
								"--tls-cert-file", "/var/run/secrets/couchbase.com/couchbase-operator-admission/tls-cert-file",
								"--tls-private-key-file", "/var/run/secrets/couchbase.com/couchbase-operator-admission/tls-private-key-file",
							}, extraArgs...),
							Ports: []corev1.ContainerPort{
								{
									Name:          "https",
									ContainerPort: 8443,
								},
							},
							VolumeMounts: []corev1.VolumeMount{
								{
									Name:      AdmissionResourceName,
									MountPath: "/var/run/secrets/couchbase.com/couchbase-operator-admission",
									ReadOnly:  true,
								},
							},
						},
					},
					Volumes: []corev1.Volume{
						{
							Name: AdmissionResourceName,
							VolumeSource: corev1.VolumeSource{
								Secret: &corev1.SecretVolumeSource{
									SecretName: AdmissionResourceName,
								},
							},
						},
					},
				},
			},
		},
	}
	if imagePullSecret != "" {
		deployment.Spec.Template.Spec.ImagePullSecrets = []corev1.LocalObjectReference{
			{
				Name: imagePullSecret,
			},
		}
	}
	return deployment
}

// GetAdmissionService returns a cluster service definition for the admission controller.
func GetAdmissionService() *corev1.Service {
	return &corev1.Service{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "v1",
			Kind:       "Service",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: AdmissionResourceName,
		},
		Spec: corev1.ServiceSpec{
			Selector: map[string]string{
				"app": AdmissionResourceName,
			},
			Ports: []corev1.ServicePort{
				{
					Protocol:   corev1.ProtocolTCP,
					Port:       443,
					TargetPort: intstr.FromInt(8443),
				},
			},
		},
	}
}

// GetAdmissionMutatingWebhook creates a mutating webhook for the admission controller.
func GetAdmissionMutatingWebhook(namespace string, ca []byte) *admissionregistrationv1beta1.MutatingWebhookConfiguration {
	admissionControllerMutatePath := "/couchbaseclusters/mutate"
	return &admissionregistrationv1beta1.MutatingWebhookConfiguration{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "admissionregistration.k8s.io/v1beta1",
			Kind:       "MutatingWebhookConfiguration",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: AdmissionResourceName,
		},
		Webhooks: []admissionregistrationv1beta1.Webhook{
			{
				Name: AdmissionResourceName + "." + namespace + ".svc",
				Rules: []admissionregistrationv1beta1.RuleWithOperations{
					{
						Rule: admissionregistrationv1beta1.Rule{
							APIGroups: []string{
								couchbasev2.GroupName,
							},
							Resources: []string{
								couchbasev2.ClusterCRDResourcePlural,
								couchbasev2.BucketCRDResourcePlural,
								couchbasev2.EphemeralBucketCRDResourcePlural,
								couchbasev2.MemcachedBucketCRDResourcePlural,
								couchbasev2.ReplicationCRDResourcePlural,
								couchbasev2.UserCRDResourcePlural,
								couchbasev2.GroupCRDResourcePlural,
								couchbasev2.RoleCRDResourcePlural,
								couchbasev2.RoleBindingCRDResourcePlural,
							},
							APIVersions: []string{
								"v1",
								"v2",
							},
						},
						Operations: []admissionregistrationv1beta1.OperationType{
							admissionregistrationv1beta1.Create,
							admissionregistrationv1beta1.Update,
						},
					},
				},
				ClientConfig: admissionregistrationv1beta1.WebhookClientConfig{
					Service: &admissionregistrationv1beta1.ServiceReference{
						Namespace: namespace,
						Name:      AdmissionResourceName,
						Path:      &admissionControllerMutatePath,
					},
					CABundle: ca,
				},
			},
		},
	}
}

